const startMs = $('Start Timer').first().json.startMs;
const checks = [];
let allPassed = true;

try {
  const r = $('Check User Service').first().json;
  const ok = !!(r?.status === 'ok' || r?.status === 'healthy' || r?.uptime);
  if (!ok) allPassed = false;
  checks.push({ name: 'user-service', ok, detail: r?.status ?? JSON.stringify(r).slice(0, 100) });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'user-service', ok: false, detail: e.message });
}

try {
  const r = $('Check PT List Endpoint').first().json;
  // PT list may return [] (empty array) — that's still a valid 200
  const ok = Array.isArray(r) || Array.isArray(r?.data) || typeof r === 'object';
  if (!ok) allPassed = false;
  checks.push({ name: 'profile/pts', ok, detail: Array.isArray(r) ? `${r.length} PTs` : (r?.error ?? 'unexpected shape') });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'profile/pts', ok: false, detail: e.message });
}

const durationMs = Date.now() - startMs;
return [{ json: {
  passed: allPassed,
  step: 'Profile',
  statusCode: allPassed ? 200 : 503,
  details: checks.map(c => `${c.name}: ${c.ok ? 'OK' : 'FAIL'}`).join(' | '),
  durationMs,
  checks
} }];
